class Solution:
    def distinctSequences(self, n: int) -> int:
        MOD = 10**9 + 7
        if n == 1:
            return 6

        # Initialize dp array to store the number of distinct sequences
        dp = [[[0]*6 for _ in range(6)] for _ in range(n)]

        # Initialize the first roll
        for i in range(6):
            dp[0][i][i] = 1

        # Calculate the number of distinct sequences for the second roll
        for i in range(6):
            for j in range(6):
                if gcd(i+1, j+1) == 1:
                    for k in range(6):
                        dp[1][j][k] += dp[0][k][i]
                        dp[1][j][k] %= MOD

        # Calculate the number of distinct sequences for the remaining rolls
        for roll in range(2, n):
            for prev in range(6):
                for prev_prev in range(6):
                    for curr in range(6):
                        if gcd(prev+1, curr+1) == 1 and prev != curr:
                            dp[roll][curr][prev] += dp[roll-1][prev][prev_prev]
                            dp[roll][curr][prev] %= MOD

        # Calculate the total number of distinct sequences
        total = 0
        for prev in range(6):
            for prev_prev in range(6):
                total += dp[n-1][prev][prev_prev]
                total %= MOD

        return total

def gcd(a, b):
    while b:
        a, b = b, a % b
    return a
